// Loop through every single item that the node receives
for (const item of items) {

  // --- Address Parsing and Cleaning ---

  // 1. Handle the Street/Apartment split
  const fullStreet = item.json.Street;
  let address1 = fullStreet;
  let address2 = item.json.Apartment || ''; 

  // **FIXED**: This regex is now more flexible to handle complex cases.
  const regex = new RegExp('\\s+(apt|apartment|suite|ste|unit|#|no\\.?).+', 'i');

  if (!address2 && fullStreet) {
    const match = fullStreet.match(regex);
    if (match) {
      // The match result is the apartment part of the address
      address2 = match[0].trim();
      // The main address is everything before the match
      address1 = fullStreet.substring(0, match.index).trim().replace(/,$/, '');
    }
  }

  // 2. Clean the address fields to remove any trailing '='
  item.json.address1 = address1 ? address1.replace(/=$/, '').trim() : '';
  item.json.address2 = address2 ? address2.replace(/=$/, '').trim() : '';

  if (item.json.City) {
      item.json.City = item.json.City.replace(/=$/, '').trim();
  }
  if (item.json.State) {
      item.json.State = item.json.State.replace(/=$/, '').trim();
  }
  if (item.json.Zip) {
      item.json.Zip = String(item.json.Zip).replace(/=$/, '').trim();
  }
  if (item.json.Country) {
      item.json.Country = item.json.Country.replace(/=$/, '').trim();
  }

  // --- Last Name Logic ---
  if (!item.json['Last Name'] || item.json['Last Name'].trim() === '') {
    item.json['Last Name'] = '.';
  }

} // The loop for the next item begins here

// Return the entire array with ALL items modified and ready for Shopify
return items;
